import React from 'react';
import { NavLink, useLocation } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import {
  LayoutDashboard, Users, Building2, CalendarDays, Clock,
  Wallet, ClipboardList, BarChart3, MessageSquare, ShieldCheck,
  ChevronLeft, ChevronRight, Megaphone, UserPlus, Target,
  Briefcase, Box, Receipt, Heart, Calendar, FileText
} from 'lucide-react';

const NAV_ITEMS = [
  { section: 'Main' },
  { path: '/dashboard', label: 'Dashboard', icon: LayoutDashboard },

  { section: 'Management' },
  { path: '/employees', label: 'Employees', icon: Users, roles: ['admin', 'hr', 'hr_staff'] },
  { path: '/departments', label: 'Departments', icon: Building2, roles: ['admin', 'hr', 'hr_staff'] },
  { path: '/recruitment', label: 'Recruitment', icon: UserSearch, roles: ['admin', 'hr'] },

  { section: 'Operations' },
  { path: '/leaves', label: 'Leaves', icon: CalendarDays },
  { path: '/attendance', label: 'Attendance', icon: Clock },
  { path: '/payroll', label: 'Payroll', icon: Wallet },
  { path: '/onboarding', label: 'Onboarding', icon: ClipboardList },
  { path: '/performance', label: 'Performance', icon: Target },

  { section: 'Communication' },
  { path: '/announcements', label: 'Announcements', icon: Megaphone },

  { section: 'Intelligence' },
  { path: '/chat', label: 'AI Assistant', icon: MessageSquare },

  { section: 'Admin' },
  { path: '/reports', label: 'Reports', icon: BarChart3, roles: ['admin', 'hr', 'director'] },
  { path: '/audit-logs', label: 'Audit Logs', icon: ShieldCheck, roles: ['admin'] },
];



const ROLE_LABELS = {
  admin: 'Admin',
  hr: 'HR Manager',
  hr_staff: 'HR Staff',
  director: 'Director',
  accountant: 'Accountant',
  employee: 'Employee',
  hod: 'HOD',
};

export default function Sidebar({ collapsed, setCollapsed, mobileOpen, setMobileOpen }) {
  const { canAccess, user } = useAuth();
  const location = useLocation();

  const filteredItems = NAV_ITEMS.filter((item) => {
    if (item.section) return true;
    if (!item.roles) return true;
    return item.roles.some((r) => canAccess(r));
  });

  const visibleItems = filteredItems.filter((item, i, arr) => {
    if (!item.section) return true;
    const next = arr[i + 1];
    return next && !next.section;
  });

  const displayName = user?.firstName
    ? `${user.firstName} ${user.lastName || ''}`.trim()
    : user?.email?.split('@')[0] || 'User';
  const roleName = user?.role?.name || 'staff';
  const roleLabel = ROLE_LABELS[roleName] || roleName;

  const initials = displayName.split(' ').filter(Boolean).map(w => w[0]).join('').toUpperCase().slice(0, 2);

  return (
    <aside
      className={`sidebar ${mobileOpen ? 'open' : ''}`}
      style={{
        width: collapsed ? 'var(--sidebar-w-collapsed)' : 'var(--sidebar-w)',
        marginLeft: 'auto'   // Pushes sidebar to right
      }}
    >
      {/* ── Mirrored Concave Active Effect ─────────────── */}
      {/* ── CSS for concave tab active effect (Flipped) ─────────────── */}
      <style>{`
  .snav-active {
    position: relative !important;
    background: linear-gradient(65deg, transparent 20px, var(--bg) 21px) !important;
    color: var(--primary) !important;
    border-radius: 0 !important;
    margin-left: 10px;
    margin-right: 0;
    box-shadow: none !important;
    transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  }

  /* Concave corner ABOVE active item - LEFT SIDE */
  .snav-active::before {
    content: '';
    position: absolute;
    left: 0;
    top: -20px;
    width: 20px;
    height: 20px;
    background: radial-gradient(circle at 0% 0%, transparent 20px, var(--bg) 21px);
    pointer-events: none;
    z-index: 1;
  }

  /* Concave corner BELOW active item - LEFT SIDE */
  .snav-active::after {
    content: '';
    position: absolute;
    left: 0;
    bottom: -20px;
    width: 20px;
    height: 20px;
    background: radial-gradient(circle at 0% 100%, transparent 20px, var(--bg) 21px);
    pointer-events: none;
    z-index: 1;
  }
`}</style>

      {/* ── Logo ──────────────────────────────────────────── */}
      <div style={{
        padding: collapsed ? '22px 0' : '22px 20px',
        display: 'flex',
        alignItems: 'center',
        gap: 12,
        justifyContent: collapsed ? 'center' : 'flex-end',   // changed
        borderBottom: '1px solid var(--sidebar-border)',
        minHeight: 72,
        flexShrink: 0,
      }}>
        {!collapsed && (
          <div style={{ animation: 'fadeIn 0.2s ease', overflow: 'hidden', textAlign: 'right' }}>
            <div style={{ fontSize: 17, fontWeight: 800, color: '#fff', letterSpacing: '-0.03em', lineHeight: 1.15 }}>UniHRM</div>
            <div style={{ fontSize: 10, color: 'rgba(255,255,255,0.45)', fontWeight: 500, letterSpacing: '0.08em', textTransform: 'uppercase' }}>HR Portal</div>
          </div>
        )}

        <div style={{
          width: 38, height: 38, borderRadius: 10,
          background: 'linear-gradient(135deg, var(--secondary) 0%, #ff8c00 100%)',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          flexShrink: 0,
          boxShadow: '0 4px 14px rgba(255,172,12,0.35)',
        }}>
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#1E1760" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
            <path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2" />
            <circle cx="9" cy="7" r="4" />
            <path d="M23 21v-2a4 4 0 0 0-3-3.87" />
            <path d="M16 3.13a4 4 0 0 1 0 7.75" />
          </svg>
        </div>
      </div>

      {/* ── Navigation ────────────────────────────────────── */}
      <nav style={{
        flex: 1, overflowY: 'auto', overflowX: 'visible',
        padding: '10px 10px 10px 0',           // mirrored padding
        display: 'flex', flexDirection: 'column', gap: 0,
      }}>
        {visibleItems.map((item, i) => {
          if (item.section) {
            if (collapsed) return <div key={`s-${i}`} style={{ height: 18 }} />;
            return (
              <div key={`s-${i}`} style={{
                fontSize: 10, fontWeight: 700,
                color: 'var(--sidebar-section)',
                textTransform: 'uppercase',
                letterSpacing: '0.12em',
                padding: '18px 10px 6px',
                textAlign: 'right',               // added
                userSelect: 'none',
              }}>
                {item.section}
              </div>
            );
          }

          const Icon = item.icon;
          const isActive = location.pathname === item.path;

          return (
            <NavLink
              key={item.path}
              to={item.path}
              title={collapsed ? item.label : undefined}
              className={isActive ? 'snav-active' : ''}
              onClick={() => setMobileOpen && setMobileOpen(false)}
              style={{
                display: 'flex',
                alignItems: 'center',
                gap: 11,
                padding: collapsed ? '10px 0' : '10px 14px',
                marginLeft: isActive ? 0 : 10,        // changed from marginRight
                marginRight: 0,
                marginBottom: 2,
                borderRadius: isActive ? '0 10px 10px 0' : 10,   // mirrored border radius
                textDecoration: 'none',
                fontSize: 13,
                fontWeight: isActive ? 700 : 500,
                justifyContent: collapsed ? 'center' : 'flex-end', // changed
                position: 'relative',
                letterSpacing: '-0.01em',
                transition: isActive ? 'none' : 'all 0.18s ease',
                background: isActive ? 'var(--bg)' : 'transparent',
                color: isActive ? 'var(--primary)' : 'var(--sidebar-text)',
                zIndex: isActive ? 2 : 'auto',
              }}
              onMouseEnter={(e) => {
                if (!isActive) {
                  e.currentTarget.style.background = 'var(--sidebar-hover)';
                  e.currentTarget.style.color = 'var(--sidebar-text-hover)';
                }
              }}
              onMouseLeave={(e) => {
                if (!isActive) {
                  e.currentTarget.style.background = 'transparent';
                  e.currentTarget.style.color = 'var(--sidebar-text)';
                }
              }}
            >
              {!collapsed && <span>{item.label}</span>}
              <Icon
                size={16}
                strokeWidth={isActive ? 2.5 : 1.8}
                style={{ flexShrink: 0 }}
              />
            </NavLink>
          );
        })}
      </nav>

      {/* User Profile & Collapse Toggle - mirrored similarly */}
      {/* ... (I can add the full mirrored bottom part if you want) ... */}

      {/* Collapse Toggle */}
      <div style={{ padding: '10px', borderTop: '1px solid var(--sidebar-border)', flexShrink: 0 }}>
        <button
          onClick={() => setCollapsed(!collapsed)}
          style={{
            width: '100%',
            display: 'flex',
            alignItems: 'center',
            justifyContent: collapsed ? 'center' : 'flex-end',   // changed
            gap: 10,
            padding: '8px 12px',
            borderRadius: 8,
            border: 'none',
            background: 'transparent',
            color: 'var(--sidebar-text)',
            fontSize: 12,
            fontWeight: 500,
            cursor: 'pointer',
          }}
          onMouseEnter={(e) => { e.currentTarget.style.background = 'var(--sidebar-hover)'; e.currentTarget.style.color = '#fff'; }}
          onMouseLeave={(e) => { e.currentTarget.style.background = 'transparent'; e.currentTarget.style.color = 'var(--sidebar-text)'; }}
        >
          {collapsed ? <ChevronLeft size={16} /> : <><span>Collapse</span><ChevronRight size={16} /></>}
        </button>
      </div>
    </aside>
  );
}
